     2→// CONVERGIO WEB - VOICE SESSION HOOK (REWRITTEN)
     3→// Azure OpenAI Realtime API with proper audio handling
     4→// ============================================================================
     5→
     6→'use client';
     7→
     8→import { useCallback, useRef, useEffect, useState } from 'react';
     9→import { logger } from '@/lib/logger';
    10→import { useVoiceSessionStore, useSettingsStore } from '@/lib/stores/app-store';
    11→import type { Maestro } from '@/types';
    12→import {
    13→  VOICE_TOOLS,
    14→  TOOL_USAGE_INSTRUCTIONS,
    15→  executeVoiceTool,
    16→  isToolCreationCommand,
    17→  isOnboardingCommand,
    18→  getToolTypeFromName,
    19→} from '@/lib/voice';
    20→import { useMethodProgressStore } from '@/lib/stores/method-progress-store';
    21→import type { ToolType as MethodToolType, HelpLevel } from '@/lib/method-progress/types';
    22→
    23→// ============================================================================
    24→// TYPES
    25→// ============================================================================
    26→
    27→interface UseVoiceSessionOptions {
    28→  onTranscript?: (role: 'user' | 'assistant', text: string) => void;
    29→  onError?: (error: Error) => void;
    30→  onStateChange?: (state: 'idle' | 'connecting' | 'connected' | 'error') => void;
    31→  onWebcamRequest?: (request: { purpose: string; instructions?: string; callId: string }) => void;
    32→  /** Disable barge-in to prevent echo loop (speaker→mic→VAD→cancel) */
    33→  disableBargeIn?: boolean;
    34→  /** Noise reduction type: 'near_field' for headphones, 'far_field' for laptop speakers with echo */
    35→  noiseReductionType?: 'near_field' | 'far_field';
    36→}
    37→
    38→interface ConnectionInfo {
    39→  provider: 'azure' | 'openai';
    40→  proxyPort?: number;
    41→  configured?: boolean;
    42→  wsUrl?: string;
    43→  token?: string;
    44→}
    45→
    46→interface ConversationMemory {
    47→  summary?: string;
    48→  keyFacts?: {
    49→    decisions?: string[];
    50→    preferences?: string[];
    51→    learned?: string[];
    52→  };
    53→  recentTopics?: string[];
    54→}
    55→
    56→// ============================================================================
    57→// CONSTANTS
    58→// ============================================================================
    59→
    60→const AZURE_SAMPLE_RATE = 24000; // Azure uses 24kHz
    61→const MAX_QUEUE_SIZE = 100; // Limit queue to prevent memory issues
    62→const CAPTURE_BUFFER_SIZE = 4096; // ~85ms at 48kHz
    63→
    64→// Audio playback tuning parameters
    65→const MIN_BUFFER_CHUNKS = 3; // Wait for N chunks before starting playback (~300ms buffer)
    66→const SCHEDULE_AHEAD_TIME = 0.1; // Schedule chunks 100ms ahead
    67→const CHUNK_GAP_TOLERANCE = 0.02; // 20ms tolerance for scheduling gaps
    68→
    69→// ============================================================================
    70→// HELPER FUNCTIONS
    71→// ============================================================================
    72→
    73→/**
    74→ * Sanitize text by removing HTML comments completely.
    75→ * Uses a loop-based approach with combined regex to handle nested/overlapping
    76→ * patterns that could bypass single-pass sanitization.
    77→ * Per CodeQL docs: combines patterns in single regex with alternation.
    78→ * Note: This sanitizes TRUSTED internal strings (maestro definitions), not user input.
    79→ * @see https://codeql.github.com/codeql-query-help/javascript/js-incomplete-multi-character-sanitization/
    80→ */
    81→function sanitizeHtmlComments(text: string): string {
    82→  let result = text;
    83→  let previousResult: string;
    84→
    85→  // Loop until no more changes occur (handles nested patterns like <!---->)
    86→  // Uses combined regex with alternation as recommended by CodeQL docs
    87→  // Handles all standard HTML comment variations including --!> (browser quirk)
    88→  do {
    89→    previousResult = result;
    90→    // Remove complete HTML comments (including --!> variant), then orphaned markers
    91→    result = result.replace(/<!--[\s\S]*?(?:--|--!)>|<!--|(?:--|--!)>/g, '');
    92→  } while (result !== previousResult);
    93→
    94→  return result;
    95→}
    96→
    97→async function fetchConversationMemory(maestroId: string): Promise<ConversationMemory | null> {
    98→  try {
    99→    const response = await fetch(`/api/conversations?maestroId=${maestroId}&limit=1`);
   100→    if (!response.ok) return null;
   101→    const conversations = await response.json();
   102→    if (!conversations || conversations.length === 0) return null;
   103→    const conv = conversations[0];
   104→    return {
   105→      summary: conv.summary,
   106→      keyFacts: conv.keyFacts ? (typeof conv.keyFacts === 'string' ? JSON.parse(conv.keyFacts) : conv.keyFacts) : undefined,
   107→      recentTopics: conv.topics ? (typeof conv.topics === 'string' ? JSON.parse(conv.topics) : conv.topics) : undefined,
   108→    };
   109→  } catch {
   110→    return null;
   111→  }
   112→}
   113→
   114→function buildMemoryContext(memory: ConversationMemory | null): string {
   115→  if (!memory) return '';
   116→  let context = '\n\n## MEMORIA DELLE CONVERSAZIONI PRECEDENTI\n';
   117→  context += 'Ricordi importanti dalle sessioni precedenti con questo studente:\n\n';
   118→  if (memory.summary) {
   119→    context += `### Riassunto:\n${memory.summary}\n\n`;
   120→  }
   121→  if (memory.keyFacts?.learned?.length) {
   122→    context += `### Concetti capiti:\n`;
   123→    memory.keyFacts.learned.forEach(l => { context += `- ${l}\n`; });
   124→    context += '\n';
   125→  }
   126→  if (memory.keyFacts?.preferences?.length) {
   127→    context += `### Preferenze:\n`;
   128→    memory.keyFacts.preferences.forEach(p => { context += `- ${p}\n`; });
   129→    context += '\n';
   130→  }
   131→  if (memory.recentTopics?.length) {
   132→    context += `### Argomenti recenti:\n`;
   133→    memory.recentTopics.forEach(t => { context += `- ${t}\n`; });
   134→    context += '\n';
   135→  }
   136→  context += `\n**USA QUESTE INFORMAZIONI** per personalizzare la lezione.\n`;
   137→  return context;
   138→}
   139→
   140→// Audio conversion utilities
   141→function base64ToInt16Array(base64: string): Int16Array {
   142→  const binaryString = atob(base64);
   143→  const bytes = new Uint8Array(binaryString.length);
   144→  for (let i = 0; i < binaryString.length; i++) {
   145→    bytes[i] = binaryString.charCodeAt(i);
   146→  }
   147→  return new Int16Array(bytes.buffer);
   148→}
   149→
   150→function int16ArrayToBase64(int16Array: Int16Array): string {
   151→  const bytes = new Uint8Array(int16Array.buffer);
   152→  let binaryString = '';
   153→  for (let i = 0; i < bytes.length; i++) {
   154→    binaryString += String.fromCharCode(bytes[i]);
   155→  }
   156→  return btoa(binaryString);
   157→}
   158→
   159→function float32ToInt16(float32Array: Float32Array): Int16Array {
   160→  const int16Array = new Int16Array(float32Array.length);
   161→  for (let i = 0; i < float32Array.length; i++) {
   162→    const sample = Math.max(-1, Math.min(1, float32Array[i]));
   163→    int16Array[i] = sample < 0 ? sample * 0x8000 : sample * 0x7FFF;
   164→  }
   165→  return int16Array;
   166→}
   167→
   168→function int16ToFloat32(int16Array: Int16Array): Float32Array {
   169→  const float32Array = new Float32Array(int16Array.length);
   170→  for (let i = 0; i < int16Array.length; i++) {
   171→    float32Array[i] = int16Array[i] / (int16Array[i] < 0 ? 0x8000 : 0x7FFF);
   172→  }
   173→  return float32Array;
   174→}
   175→
   176→function resample(inputData: Float32Array, fromRate: number, toRate: number): Float32Array {
   177→  if (fromRate === toRate) return inputData;
   178→  const ratio = fromRate / toRate;
   179→  const outputLength = Math.floor(inputData.length / ratio);
   180→  const output = new Float32Array(outputLength);
   181→  for (let i = 0; i < outputLength; i++) {
   182→    const srcIndex = i * ratio;
   183→    const srcIndexFloor = Math.floor(srcIndex);
   184→    const srcIndexCeil = Math.min(srcIndexFloor + 1, inputData.length - 1);
   185→    const fraction = srcIndex - srcIndexFloor;
   186→    output[i] = inputData[srcIndexFloor] * (1 - fraction) + inputData[srcIndexCeil] * fraction;
   187→  }
   188→  return output;
   189→}
