   270→  const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
   271→
   272→  // ============================================================================
   273→  // AUDIO PLAYBACK (at 24kHz) - SYNC VERSION (like test page that works!)
   274→  // ============================================================================
   275→
   276→  const initPlaybackContext = useCallback(async () => {
   277→    if (playbackContextRef.current) {
   278→      // Resume if suspended (browser policy requires user interaction)
   279→      if (playbackContextRef.current.state === 'suspended') {
   280→        logger.debug('[VoiceSession] 🔊 Resuming suspended AudioContext...');
   281→        await playbackContextRef.current.resume();
   282→      }
   283→      return playbackContextRef.current;
   284→    }
   285→
   286→    const AudioContextClass = window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
   287→    // CRITICAL: Create playback context at 24kHz to match Azure output
   288→    playbackContextRef.current = new AudioContextClass({ sampleRate: AZURE_SAMPLE_RATE });
   289→    logger.debug(`[VoiceSession] 🔊 Playback context created at ${AZURE_SAMPLE_RATE}Hz, state: ${playbackContextRef.current.state}`);
   290→
   291→    // Set output device if specified (setSinkId API)
   292→    if (preferredOutputId && 'setSinkId' in playbackContextRef.current) {
   293→      try {
   294→        await (playbackContextRef.current as AudioContext & { setSinkId: (id: string) => Promise<void> }).setSinkId(preferredOutputId);
   295→        logger.debug(`[VoiceSession] 🔊 Audio output set to device: ${preferredOutputId}`);
   296→      } catch (err) {
   297→        logger.warn('[VoiceSession] ⚠️ Could not set output device, using default', { err });
   298→      }
   299→    }
   300→
   301→    // Resume immediately if suspended
   302→    if (playbackContextRef.current.state === 'suspended') {
   303→      logger.debug('[VoiceSession] 🔊 Resuming new AudioContext...');
   304→      await playbackContextRef.current.resume();
   305→    }
   306→
   307→    return playbackContextRef.current;
   308→  }, [preferredOutputId]);
   309→
   310→  // =========================================================================
   311→  // TIME-BASED SCHEDULED PLAYBACK
   312→  // Uses AudioContext.currentTime for precise scheduling to prevent stuttering
   313→  // =========================================================================
   314→
   315→  // Schedule all queued chunks for playback
   316→  const scheduleQueuedChunks = useCallback(() => {
   317→    const ctx = playbackContextRef.current;
   318→    if (!ctx || audioQueueRef.current.length === 0) return;
   319→
   320→    const currentTime = ctx.currentTime;
   321→
   322→    // Schedule chunks from queue
   323→    while (audioQueueRef.current.length > 0) {
   324→      const audioData = audioQueueRef.current.shift()!;
   325→      const float32Data = int16ToFloat32(audioData);
   326→
   327→      // Create buffer at 24kHz
   328→      const buffer = ctx.createBuffer(1, float32Data.length, AZURE_SAMPLE_RATE);
   329→      buffer.getChannelData(0).set(float32Data);
   330→
   331→      const source = ctx.createBufferSource();
   332→      source.buffer = buffer;
   333→      source.connect(ctx.destination);
   334→
   335→      // Calculate chunk duration
   336→      const chunkDuration = float32Data.length / AZURE_SAMPLE_RATE;
   337→
   338→      // Determine when to play this chunk
   339→      // If we're behind schedule, catch up; otherwise schedule ahead
   340→      if (nextPlayTimeRef.current < currentTime + CHUNK_GAP_TOLERANCE) {
   341→        nextPlayTimeRef.current = currentTime + SCHEDULE_AHEAD_TIME;
   342→      }
   343→
   344→      try {
   345→        source.start(nextPlayTimeRef.current);
   346→        scheduledSourcesRef.current.push(source);
   347→
   348→        // Clean up finished sources to prevent memory leak
   349→        source.onended = () => {
   350→          const idx = scheduledSourcesRef.current.indexOf(source);
   351→          if (idx > -1) scheduledSourcesRef.current.splice(idx, 1);
   352→
   353→          // Check if all playback is done
   354→          if (scheduledSourcesRef.current.length === 0 && audioQueueRef.current.length === 0) {
   355→            isPlayingRef.current = false;
   356→            isBufferingRef.current = true; // Reset to buffering for next response
   357→            setSpeaking(false);
   358→            setOutputLevel(0);
   359→          }
   360→        };
   361→
   362→        // Update next play time
   363→        nextPlayTimeRef.current += chunkDuration;
   364→
   365→      } catch (e) {
   366→        logger.error('[VoiceSession] Playback scheduling error', { error: e });
   367→      }
   368→
   369→      // Calculate and update output level (RMS)
   370→      let sumSquares = 0;
   371→      for (let i = 0; i < float32Data.length; i++) {
   372→        sumSquares += float32Data[i] * float32Data[i];
   373→      }
   374→      const rms = Math.sqrt(sumSquares / float32Data.length);
   375→      setOutputLevel(Math.min(rms * 5, 1));
   376→    }
   377→  }, [setSpeaking, setOutputLevel]);
   378→
   379→  // Legacy playNextChunk - now triggers scheduled playback
   380→  const playNextChunk = useCallback(() => {
   381→    const ctx = playbackContextRef.current;
   382→
   383→    if (!ctx || audioQueueRef.current.length === 0) {
   384→      // Check if there are still scheduled sources playing
   385→      if (scheduledSourcesRef.current.length === 0) {
   386→        isPlayingRef.current = false;
   387→        setSpeaking(false);
   388→        setOutputLevel(0);
   389→      }
   390→      return;
   391→    }
   392→
   393→    // If we're in buffering mode, wait for enough chunks
   394→    if (isBufferingRef.current && audioQueueRef.current.length < MIN_BUFFER_CHUNKS) {
   395→      logger.debug(`[VoiceSession] Buffering... ${audioQueueRef.current.length}/${MIN_BUFFER_CHUNKS} chunks`);
   396→      return;
   397→    }
   398→
   399→    // Exit buffering mode and start scheduled playback
   400→    if (isBufferingRef.current) {
   401→      isBufferingRef.current = false;
   402→      nextPlayTimeRef.current = ctx.currentTime + SCHEDULE_AHEAD_TIME;
   403→      logger.debug(`[VoiceSession] Buffer ready, starting scheduled playback at ${nextPlayTimeRef.current.toFixed(3)}`);
   404→    }
   405→
   406→    isPlayingRef.current = true;
   407→    setSpeaking(true);
   408→
   409→    // Schedule all queued chunks
   410→    scheduleQueuedChunks();
   411→  }, [setSpeaking, setOutputLevel, scheduleQueuedChunks]);
   412→
   413→  // Keep ref updated with latest playNextChunk
   414→  useEffect(() => {
   415→    playNextChunkRef.current = playNextChunk;
   416→  }, [playNextChunk]);
