   418→  // ============================================================================
   419→  // AUDIO CAPTURE (at native rate, resample to 24kHz)
   420→  // ============================================================================
   421→
   422→  const startAudioCapture = useCallback(() => {
   423→    if (!captureContextRef.current || !mediaStreamRef.current) {
   424→      logger.warn('[VoiceSession] Cannot start capture: missing context or stream');
   425→      return;
   426→    }
   427→
   428→    const context = captureContextRef.current;
   429→    const nativeSampleRate = context.sampleRate;
   430→    logger.debug(`[VoiceSession] Starting audio capture at ${nativeSampleRate}Hz, resampling to ${AZURE_SAMPLE_RATE}Hz`);
   431→
   432→    const source = context.createMediaStreamSource(mediaStreamRef.current);
   433→    sourceNodeRef.current = source;
   434→
   435→    // Create analyser for input levels
   436→    analyserRef.current = context.createAnalyser();
   437→    analyserRef.current.fftSize = 256;
   438→    source.connect(analyserRef.current);
   439→
   440→    // Create processor for audio capture
   441→    const processor = context.createScriptProcessor(CAPTURE_BUFFER_SIZE, 1, 1);
   442→    processorRef.current = processor;
   443→
   444→    processor.onaudioprocess = (event) => {
   445→      if (wsRef.current?.readyState !== WebSocket.OPEN) return;
   446→      if (isMuted) return;
   447→
   448→      const inputData = event.inputBuffer.getChannelData(0);
   449→
   450→      // Resample from native rate to 24kHz
   451→      const resampledData = resample(inputData, nativeSampleRate, AZURE_SAMPLE_RATE);
   452→
   453→      // Convert to PCM16 and base64
   454→      const int16Data = float32ToInt16(resampledData);
   455→      const base64 = int16ArrayToBase64(int16Data);
   456→
   457→      // Send to Azure
   458→      wsRef.current.send(JSON.stringify({
   459→        type: 'input_audio_buffer.append',
   460→        audio: base64,
   461→      }));
   462→
   463→      // Update input level (throttled)
   464→      const now = performance.now();
   465→      if (now - lastLevelUpdateRef.current > 50 && analyserRef.current) {
   466→        lastLevelUpdateRef.current = now;
   467→        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
   468→        analyserRef.current.getByteFrequencyData(dataArray);
   469→        const average = dataArray.reduce((a, b) => a + b, 0) / dataArray.length;
   470→        setInputLevel(average / 255);
   471→      }
   472→    };
   473→
   474→    source.connect(processor);
   475→    processor.connect(context.destination);
   476→    logger.debug('[VoiceSession] Audio capture started');
   477→  }, [isMuted, setInputLevel]);
   478→
   479→  // ============================================================================
