   591→    // See: https://learn.microsoft.com/en-us/azure/ai-services/openai/realtime-audio-reference
   592→    const sessionConfig = {
   593→      type: 'session.update',
   594→      session: {
   595→        voice: maestro.voice || 'alloy',
   596→        instructions: fullInstructions,
   597→        input_audio_format: 'pcm16',
   598→        output_audio_format: 'pcm16',
   599→        // Noise reduction to prevent echo (new feature Dec 2025)
   600→        // 'near_field' for headphones/close mic, 'far_field' for laptop/conference
   601→        input_audio_noise_reduction: {
   602→          type: options.noiseReductionType || 'near_field',
   603→        },
   604→        input_audio_transcription: {
   605→          model: 'whisper-1',
   606→          language: language,  // Force transcription to use the language from settings
   607→        },
   608→        turn_detection: {
