   619→    };
   620→
   621→    logger.debug('[VoiceSession] Sending session.update to Azure, instructions length:', { instructionsLength: fullInstructions.length });
   622→    logger.debug('[VoiceSession] Session config', { configPreview: JSON.stringify(sessionConfig).slice(0, 500) });
   623→    ws.send(JSON.stringify(sessionConfig));
   624→
   625→    // Don't start audio capture yet - wait for session.updated
   626→    // startAudioCapture() will be called when session.updated is received
   627→
   628→    setConnected(true);
   629→    setCurrentMaestro(maestro);
