   633→
   634→  const handleServerEvent = useCallback((event: Record<string, unknown>) => {
   635→    const eventType = event.type as string;
   636→    logger.debug(`[VoiceSession] >>> handleServerEvent called with type: ${eventType}`);
   637→
   638→    switch (eventType) {
   639→      case 'proxy.ready':
   640→        logger.debug('[VoiceSession] Proxy connected to Azure, sending session config...');
   641→        // NOW we can send session.update - proxy<->Azure connection is established
   642→        sendSessionConfig();
   643→        break;
   644→
   645→      case 'session.created':
   646→        logger.debug('[VoiceSession] Session created');
   647→        break;
   648→
   649→      case 'session.updated':
   650→        logger.debug('[VoiceSession] Session configured, ready for conversation');
   651→        logger.debug('[VoiceSession] Full session.updated event', { eventPreview: JSON.stringify(event).slice(0, 500) });
   652→        sessionReadyRef.current = true;
   653→        // NOW start audio capture - session is properly configured
   654→        logger.debug('[VoiceSession] Starting audio capture...');
   655→        startAudioCapture();
   656→        // Now that session is ready, send greeting after a brief delay
   657→        logger.debug('[VoiceSession] Will send greeting in 300ms...');
   658→        setTimeout(() => sendGreeting(), 300);
   659→        break;
   660→
   661→      case 'response.created':
   662→        // Azure has started generating a response - track this for proper cancellation
   663→        hasActiveResponseRef.current = true;
   664→        logger.debug('[VoiceSession] Response created - hasActiveResponse = true');
   665→        break;
   666→
   667→      case 'input_audio_buffer.speech_started':
   668→        logger.debug('[VoiceSession] User speech detected');
   669→        setListening(true);
   670→
